export const MAP_VIEW = { w: 1000, h: 694.9 };

// Projeksjonen speiles i projectPoint() så prikker treffer samme rom som omrisset.
const LNG_MIN = -128.5, LAT_MAX = 52.5, K = 15.384615;
const RAD = Math.PI / 180;
const mercY = (lat) => Math.log(Math.tan(Math.PI / 4 + (lat * RAD) / 2));
const Y_TOP = mercY(LAT_MAX);
export function projectPoint(lat, lng) {
  return { x: (lng - LNG_MIN) * K, y: ((Y_TOP - mercY(lat)) / RAD) * K };
}

